{
  "terms": [
    {
      "term": "Ring Final Circuit",
      "simpleDefinition": "A circuit where the live conductors form a continuous loop, starting and ending at the same point in the distribution board.",
      "anchor": "A continuous loop of cable serving multiple socket outlets.",
      "misconception": "Believing all power circuits must be rings; radial circuits are also frequently used for power."
    },
    {
      "term": "Radial Circuit",
      "simpleDefinition": "A circuit that runs from the distribution board to the outlets and stops at the final point without returning.",
      "anchor": "A 'dead-end' circuit path, similar to a branch on a tree.",
      "misconception": "Thinking radials are only for lighting; they are often used for high-power appliances like cookers."
    },
    {
      "term": "SWA (Steel Wire Armoured)",
      "simpleDefinition": "A heavy-duty cable protected by a layer of galvanized steel wire to prevent mechanical damage.",
      "anchor": "The 'armoured' cable used for underground runs or industrial power.",
      "misconception": "Thinking the steel wire is only for the Earth connection; its primary purpose is physical protection."
    },
    {
      "term": "MICC (Mineral Insulated Copper Clad)",
      "simpleDefinition": "A fireproof cable using copper conductors inside a copper sheath with compressed magnesium oxide insulation.",
      "anchor": "The 'fireproof' cable used for emergency systems and high-heat areas.",
      "misconception": "Thinking it is standard cable; it requires specialized seals to prevent moisture from ruining the powder insulation."
    },
    {
      "term": "Conduit and Trunking",
      "simpleDefinition": "Protective enclosures (tubes or rectangular channels) used to route and protect individual cables.",
      "anchor": "The 'protective skeleton' of a wiring system in commercial or industrial sites.",
      "misconception": "Thinking they are just for tidiness; they provide essential mechanical protection and fire containment."
    },
    {
      "term": "Wiring System",
      "simpleDefinition": "The specific combination of cables and their containment method chosen for a particular environment.",
      "anchor": "Matching the cable protection to the environment, such as using steel in a factory or plastic in a house.",
      "misconception": "Thinking one wiring type is suitable for all environments; hazardous or agricultural sites require specific systems."
    }
  ],
  "anchorPhrases": [
    "A ring final circuit forms a continuous loop.",
    "A radial circuit ends at the last point of use.",
    "SWA provides mechanical protection for harsh environments.",
    "MICC is used where fire resistance is critical.",
    "Conduit and trunking are types of cable containment.",
    "Wiring systems must be selected based on the specific environment."
  ],
  "misconceptionTargets": [
    "Confusing ring circuits with radial circuits.",
    "Assuming SWA armour is only for earthing rather than protection.",
    "Treating MICC like standard PVC cable regarding moisture.",
    "Believing any wiring system is safe for hazardous or agricultural environments."
  ]
}

{
  "teachChecks": [
    {
      "title": "Circuit Types: Radial and Ring Final",
      "objective": "Explain the principles of operation for radial and ring final circuits.",
      "retrievalTextLines": [
        "In electrical installations, we use different circuit layouts depending on the load and application. A Radial Circuit runs from the distribution board to the first outlet, then the second, and stops at the final point. It is like a branch on a tree. We commonly use radials for lighting and high-power fixed appliances like cookers or water heaters.",
        "A Ring Final Circuit is unique because the live conductors form a continuous loop. They start at the distribution board, visit every socket in the circuit, and return to the same terminal in the board. This loop allows current to flow in two directions to reach any single socket. Because the load is shared between these two paths, we can use thinner cables than a radial would require for the same total current. A key advantage is redundancy: if one part of the ring breaks, the sockets still receive power from the other side of the loop, although the cable may then become overloaded."
      ],
      "hint": "Think about whether the cable returns to the distribution board or ends at the last socket."
    },
    {
      "title": "Wiring Systems and Environments",
      "objective": "Identify wiring systems and their suitability for different environments.",
      "retrievalTextLines": [
        "Wiring systems must be selected to suit their environment. In industrial sites where physical damage is likely, we use SWA (Steel Wire Armoured) cable. The 'armour' is a layer of galvanized steel wires that provides mechanical protection against impacts and allows the cable to be buried underground safely.",
        "For emergency systems, we use MICC (Mineral Insulated Copper Clad) cable. MICC uses compressed magnesium oxide powder as insulation inside a copper sheath. Because it contains no plastic, it is fireproof and survives extreme heat. In commercial buildings, we often use Conduit (protective tubes) and Trunking (rectangular channels). These act as a protective skeleton for 'single-core' cables. This system allows electricians to pull in new wires or replace old ones easily without damaging the building structure. In specialized areas like farms (agricultural), wiring must resist moisture and chemical corrosion from animal waste, often requiring heavy-duty plastic or non-corrosive enclosures."
      ],
      "hint": "Consider the specific protection offered by steel armour versus mineral insulation."
    }
  ]
}

